class Solution:
    def maximumScoreAfterOperations(self, edges, values):
        n = len(values)
        adj = [[] for _ in range(n)]
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)
        total = sum(values)
        parent = [-1] * n
        visited = [False] * n
        order = []
        stack = [0]
        visited[0] = True
        while stack:
            node = stack.pop()
            order.append(node)
            for nxt in adj[node]:
                if not visited[nxt]:
                    visited[nxt] = True
                    parent[nxt] = node
                    stack.append(nxt)
        dp = [0] * n
        for node in reversed(order):
            children = [c for c in adj[node] if c != parent[node]]
            if not children:
                dp[node] = values[node]
            else:
                dp[node] = min(values[node], sum(dp[c] for c in children))
        return total - dp[0]

