var maximumScoreAfterOperations = function(edges, values) {
    const n = values.length;
    const adj = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }
    let total = 0;
    for (const v of values) total += v;
    const parent = new Array(n).fill(-1);
    const visited = new Array(n).fill(false);
    const order = [];
    const stack = [0];
    visited[0] = true;
    while (stack.length) {
        const node = stack.pop();
        order.push(node);
        for (const nxt of adj[node]) {
            if (!visited[nxt]) {
                visited[nxt] = true;
                parent[nxt] = node;
                stack.push(nxt);
            }
        }
    }
    const dp = new Array(n).fill(0);
    for (let idx = order.length - 1; idx >= 0; idx--) {
        const node = order[idx];
        const children = adj[node].filter((c) => c !== parent[node]);
        if (children.length === 0) {
            dp[node] = values[node];
        } else {
            let childSum = 0;
            for (const c of children) childSum += dp[c];
            dp[node] = Math.min(values[node], childSum);
        }
    }
    return total - dp[0];
};
